import QtQuick
import QtQuick.Layouts
import Quickshell
import Quickshell.Services.Pipewire
import Quickshell.Wayland
import qs.src.services

Scope {
    id: root
    required property var screen

    PwObjectTracker {
        objects: [ Pipewire.defaultAudioSink ]
    }

    readonly property var audio: Pipewire.defaultAudioSink?.audio
    property bool visibleState: false

    Connections {
        target: audio
        function onVolumeChanged() { triggerShow(); }
        function onMutedChanged() { triggerShow(); }
    }

    function triggerShow() {
        visibleState = true;
        hideTimer.restart();
    }

    Timer {
        id: hideTimer
        interval: 2000
        onTriggered: visibleState = false
    }

    PanelWindow {
        id: win
        screen: root.screen
        visible: visibleState

        WlrLayershell.layer: WlrLayer.Overlay
        WlrLayershell.namespace: "hyprui-osd"

        // Window spans the bottom edge
        anchors {
            bottom: true
            left: true
            right: true
        }

        implicitHeight: 120
        color: "transparent"

        // Standard QML Rectangle centered inside the full-width window
        Rectangle {
            id: container
            anchors.horizontalCenter: parent.horizontalCenter
            anchors.bottom: parent.bottom
            anchors.bottomMargin: 30 // Gap from the screen edge

            width: 300
            height: 70

            radius: Theme.rounding
            color: Theme.background
            border.color: Theme.primary
            border.width: 2

            opacity: visibleState ? 1.0 : 0.0
            scale: visibleState ? 1.0 : 0.9

            Behavior on opacity { NumberAnimation { duration: Theme.anim.fast } }
            Behavior on scale { NumberAnimation { duration: Theme.anim.fast; easing.type: Theme.anim.curve } }
            Behavior on color { ColorAnimation { duration: Theme.anim.normal } }
            Behavior on border.color { ColorAnimation { duration: Theme.anim.normal } }
            Behavior on radius { NumberAnimation { duration: Theme.anim.normal } }

            RowLayout {
                anchors.fill: parent
                anchors.margins: 15
                spacing: 12

                Text {
                    text: audio?.muted ? "󰝟" : "󰕾"
                    font.pixelSize: 24
                    color: audio?.muted ? Theme.error : Theme.primary
                    verticalAlignment: Text.AlignVCenter

                    Behavior on color { ColorAnimation { duration: Theme.anim.normal } }
                }

                Rectangle {
                    Layout.fillWidth: true
                    Layout.preferredHeight: 10
                    radius: 5
                    color: Theme.surface

                    Rectangle {
                        width: parent.width * (audio?.volume ?? 0)
                        height: parent.height
                        radius: parent.radius
                        color: Theme.primary

                        Behavior on width { 
                            NumberAnimation { duration: 100; easing.type: Easing.OutQuad } 
                        }
                        Behavior on color { ColorAnimation { duration: Theme.anim.normal } }
                    }
                }

                Text {
                    text: Math.round((audio?.volume ?? 0) * 100) + "%"
                    font.pixelSize: 14
                    font.bold: true
                    color: Theme.text
                    width: 35
                    horizontalAlignment: Text.AlignRight
                }
            }
        }
    }
}

