pragma Singleton
import QtQuick
import Quickshell

Singleton {
    id: root

    // Active Theme Switcher
    property string current: "mocha"

    readonly property var themes: ({
        "mocha": {
            name: "Catppuccin Mocha",
            primary: "#cba6f7",
            secondary: "#fab387",
            background: "#1e1e2e",
            surface: "#313244",
            text: "#cdd6f4",
            error: "#f38ba8",
            rounding: 16
        },
        "dracula": {
            name: "Dracula",
            primary: "#bd93f9",
            secondary: "#ffb86c",
            background: "#282a36",
            surface: "#44475a",
            text: "#f8f8f2",
            error: "#ff5555",
            rounding: 12
        },
        "tokyonight": {
            name: "Tokyo Night",
            primary: "#7aa2f7",
            secondary: "#bb9af7",
            background: "#1a1b26",
            surface: "#24283b",
            text: "#c0caf5",
            error: "#f7768e",
            rounding: 20
        }
    })

    readonly property var active: themes[current]

    // Snappy transitions from your HyprNotify project
    readonly property var anim: ({
        snappy: 20, // 0.02s
        normal: 300,
        curve: Easing.OutQuint
    })

    function cycle() {
        let keys = Object.keys(themes);
        current = keys[(keys.indexOf(current) + 1) % keys.length];
    }
}

