pragma Singleton
import Quickshell
import Quickshell.Services.Pipewire
import QtQuick

Singleton {
    id: root

    readonly property var sinks: Pipewire.nodes.values.filter(node => !node.isStream && node.isSink)
    readonly property var sources: Pipewire.nodes.values.filter(node => !node.isStream && node.audio && !node.isSink)
    readonly property var streams: Pipewire.nodes.values.filter(node => node.isStream && node.audio)

    readonly property PwNode sink: Pipewire.defaultAudioSink
    readonly property PwNode source: Pipewire.defaultAudioSource

    readonly property bool muted: !!sink?.audio?.muted
    readonly property real volume: sink?.audio?.volume ?? 0

    function setVolume(newVolume: real): void {
        if (sink?.ready && sink?.audio) {
            sink.audio.muted = false;
            sink.audio.volume = Math.max(0, Math.min(1.5, newVolume)); // Max 150%
        }
    }

    function toggleMute(): void {
        if (sink?.audio) sink.audio.muted = !sink.audio.muted;
    }

    PwObjectTracker {
        objects: [Pipewire.defaultAudioSink, Pipewire.defaultAudioSource]
    }
}

import QtQuick
import QtQuick.Layouts
import Quickshell
import Quickshell.Wayland
import "../services"

Scope {
    id: root
    required property var screen

    // Direct binding to our sanitized Audio singleton
    readonly property bool visibleState: hideTimer.running

    Connections {
        target: Audio
        function onVolumeChanged() { hideTimer.restart(); }
        function onMutedChanged() { hideTimer.restart(); }
    }

    Timer {
        id: hideTimer
        interval: 1800
    }

    PanelWindow {
        id: win
        screen: root.screen
        visible: visibleState

        WlrLayershell.layer: WlrLayer.Overlay
        WlrLayershell.namespace: "hyprui-osd"
        WlrLayershell.exclusiveZone: -1

        anchors {
            bottom: true
            left: true
            right: true
        }

        implicitHeight: 120
        color: "transparent"

        Rectangle {
            id: container
            anchors.horizontalCenter: parent.horizontalCenter
            anchors.bottom: parent.bottom
            anchors.bottomMargin: 40

            width: 320
            height: 70

            radius: HyprUITheme.active.rounding
            color: HyprUITheme.active.background
            border.color: HyprUITheme.active.primary
            border.width: 1.5

            opacity: visibleState ? 1.0 : 0.0
            scale: visibleState ? 1.0 : 0.85

            Behavior on opacity { NumberAnimation { duration: 150 } }
            Behavior on scale { NumberAnimation { duration: 150; easing.type: Easing.OutBack } }
            Behavior on color { ColorAnimation { duration: 300 } }
            Behavior on border.color { ColorAnimation { duration: 300 } }

            RowLayout {
                anchors.fill: parent
                anchors.margins: 15
                spacing: 12

                Text {
                    text: Audio.muted ? "󰝟" : "󰕾"
                    font.pixelSize: 22
                    color: Audio.muted ? HyprUITheme.active.error : HyprUITheme.active.primary
                }

                Rectangle {
                    Layout.fillWidth: true
                    Layout.preferredHeight: 8
                    radius: 4
                    color: HyprUITheme.active.surface

                    Rectangle {
                        width: parent.width * Math.min(Audio.volume, 1.0)
                        height: parent.height
                        radius: 4
                        color: HyprUITheme.active.primary

                        Behavior on width { NumberAnimation { duration: 100 } }
                    }
                }

                Text {
                    text: Math.round(Audio.volume * 100) + "%"
                    font.pixelSize: 14
                    font.bold: true
                    color: HyprUITheme.active.text
                    width: 35
                }
            }
        }
    }
}

