import QtQuick
import QtQuick.Layouts
import QtQuick.Effects
import Quickshell
import Quickshell.Wayland
import Quickshell.Services.Mpris
import "../services"

Scope {
    id: root
    required property QuickshellScreenInfo screen

    readonly property MprisPlayer player: Mpris.players.values[0] ?? null
    readonly property bool hasPlayer: !!player

    // Auto-show when metadata changes, then hide
    property bool active: false

    Connections {
        target: player
        function onMetadataChanged() {
            active = true;
            hideTimer.restart();
        }
    }

    Timer {
        id: hideTimer
        interval: 5000
        onTriggered: active = false
    }

    PanelWindow {
        id: win
        screen: root.screen
        visible: active || (player?.playbackStatus === MprisPlaybackStatus.Playing)

        WlrLayershell.layer: WlrLayer.Overlay
        WlrLayershell.namespace: "hyprui-media"
        WlrLayershell.exclusiveZone: -1

        anchors {
            top: true
            right: true
        }

        implicitWidth: 400
        implicitHeight: 180
        color: "transparent"

        Rectangle {
            id: container
            anchors.fill: parent
            anchors.margins: 20

            radius: HyprUITheme.active.rounding
            color: HyprUITheme.active.background
            opacity: 0.95
            border.color: HyprUITheme.active.primary
            border.width: 1

            RowLayout {
                anchors.fill: parent
                anchors.margins: 15
                spacing: 15

                // Album Art with Rounded Corners
                Rectangle {
                    width: 100
                    height: 100
                    radius: HyprUITheme.active.rounding / 2
                    clip: true
                    color: HyprUITheme.active.surface

                    Image {
                        anchors.fill: parent
                        source: player?.artUrl ?? ""
                        fillMode: Image.PreserveAspectCrop
                        asynchronous: true

                        Text {
                            visible: parent.status !== Image.Ready
                            anchors.centerIn: parent
                            text: "󰝚"
                            font.pixelSize: 40
                            color: HyprUITheme.active.text
                            opacity: 0.3
                        }
                    }
                }

                // Metadata & Controls
                ColumnLayout {
                    Layout.fillWidth: true
                    spacing: 5

                    Text {
                        Layout.fillWidth: true
                        text: player?.trackTitle ?? "Not Playing"
                        font.pixelSize: 18
                        font.bold: true
                        color: HyprUITheme.active.text
                        elide: Text.ElideRight
                    }

                    Text {
                        Layout.fillWidth: true
                        text: player?.trackArtists.join(", ") ?? "Unknown Artist"
                        font.pixelSize: 14
                        color: HyprUITheme.active.text
                        opacity: 0.7
                        elide: Text.ElideRight
                    }

                    Item { Layout.fillHeight: true }

                    // Progress Bar
                    Rectangle {
                        Layout.fillWidth: true
                        Layout.preferredHeight: 4
                        radius: 2
                        color: HyprUITheme.active.surface

                        Rectangle {
                            width: parent.width * (player?.position / player?.length || 0)
                            height: parent.height
                            radius: 2
                            color: HyprUITheme.active.primary
                        }
                    }

                    // Media Controls
                    RowLayout {
                        Layout.alignment: Qt.AlignHCenter
                        spacing: 20

                        Text {
                            text: "󰒮"
                            font.pixelSize: 20
                            color: HyprUITheme.active.text
                            MouseArea { anchors.fill: parent; onClicked: player?.previous() }
                        }

                        Text {
                            text: player?.playbackStatus === MprisPlaybackStatus.Playing ? "󰏤" : "󰐊"
                            font.pixelSize: 30
                            color: HyprUITheme.active.primary
                            MouseArea { anchors.fill: parent; onClicked: player?.playPause() }
                        }

                        Text {
                            text: "󰒭"
                            font.pixelSize: 20
                            color: HyprUITheme.active.text
                            MouseArea { anchors.fill: parent; onClicked: player?.next() }
                        }
                    }
                }
            }
        }
    }
}

