            surface: "#44475a",
            text: "#f8f8f2",
            error: "#ff5555",
            rounding: 24,
            accents: {
                volume: "#bd93f9",
                brightness: "#f1fa8c"
            }
        },
        "tokyonight": {
            name: "Tokyo Night",
            background: "#1a1b26",
            surface: "#414868",
            text: "#c0caf5",
            error: "#f7768e",
            rounding: 24,
            accents: {
                volume: "#7aa2f7",
                brightness: "#e0af68"
            }
        }
    })

    readonly property var active: themes[current]

    // Convenience properties to avoid deep nesting
    readonly property color primary: active.accents.volume
    readonly property color secondary: active.accents.brightness

    readonly property var anim: ({
        fast: 150,
        normal: 300,
        curve: Easing.OutQuint
    })

    function cycle() {
        let keys = Object.keys(themes);
        current = keys[(keys.indexOf(current) + 1) % keys.length];
    }
}

import QtQuick
import QtQuick.Layouts
import Quickshell
import Quickshell.Wayland
import "../services"

Scope {
    id: root
    required property QuickshellScreenInfo screen

    readonly property bool isSegmented: HyprUITheme.active.segmented ?? false
    readonly property bool visibleState: hideTimer.running

    Connections {
        target: Audio
        function onVolumeChanged() { hideTimer.restart(); }
        function onMutedChanged() { hideTimer.restart(); }
    }

    Timer {
        id: hideTimer
        interval: 1800
    }

    PanelWindow {
        id: win
        screen: root.screen
        visible: visibleState

        WlrLayershell.layer: WlrLayer.Overlay
        WlrLayershell.namespace: "hyprui-osd"
        WlrLayershell.exclusiveZone: -1

        anchors {
            bottom: true
            left: true
            right: true
        }

        implicitHeight: 120
        color: "transparent"

        Rectangle {
            id: container
            anchors.horizontalCenter: parent.horizontalCenter
            anchors.bottom: parent.bottom
            anchors.bottomMargin: 40

            width: 320
            height: 70

            radius: HyprUITheme.active.rounding
            color: HyprUITheme.active.background
            border.color: HyprUITheme.active.accents.volume
            border.width: isSegmented ? 0 : 1.5

            opacity: visibleState ? 1.0 : 0.0
            scale: visibleState ? 1.0 : 0.85

            Behavior on opacity { NumberAnimation { duration: 150 } }
            Behavior on scale { NumberAnimation { duration: 150; easing.type: Easing.OutBack } }

            RowLayout {
                anchors.fill: parent
                anchors.margins: 15
                spacing: 12

                Text {
                    text: Audio.muted ? "󰝟" : "󰕾"
                    font.pixelSize: 22
                    color: Audio.muted ? HyprUITheme.active.error : HyprUITheme.active.accents.volume
                }

                // Bar Layout
                Row {
                    Layout.fillWidth: true
                    Layout.preferredHeight: isSegmented ? 24 : 8
                    spacing: isSegmented ? 4 : 0

                    // Standard Bar
                    Rectangle {
                        visible: !isSegmented
                        width: parent.width
                        height: parent.height
                        radius: 4
                        color: HyprUITheme.active.surface

                        Rectangle {
                            width: parent.width * Math.min(Audio.volume, 1.0)
                            height: parent.height
                            radius: 4
                            color: HyprUITheme.active.accents.volume
                            Behavior on width { NumberAnimation { duration: 100 } }
                        }
                    }

                    // Segmented macOS Bar
                    Repeater {
                        model: isSegmented ? 16 : 0
                        Rectangle {
                            width: (parent.width - (15 * 4)) / 16
                            height: parent.height
                            radius: 2
                            color: (index / 16) < Audio.volume ? HyprUITheme.active.accents.volume : "rgba(69, 71, 90, 0.3)"
                        }
                    }
                }

                Text {
                    text: Math.round(Audio.volume * 100) + "%"
                    font.pixelSize: 14
                    font.bold: true
                    color: HyprUITheme.active.text
                    width: 35
                }
            }
        }
    }
}

